codeExercises.solution:
import React from 'react';

// Giải thích: Sử dụng path import (import trực tiếp từ đường dẫn) cho từng component.
// Lý do: Phương pháp này cho phép công cụ build (như Webpack) thực hiện "tree-shaking",
// loại bỏ các component không sử dụng từ bundle cuối cùng. Điều này giúp giảm đáng kể
// kích thước file JavaScript, dẫn đến tải trang nhanh hơn và cải thiện hiệu năng tổng thể.
import TextField from '@mui/material/TextField';
import Button from '@mui/material/Button';
import Checkbox from '@mui/material/Checkbox';
import FormControlLabel from '@mui/material/FormControlLabel';
import Box from '@mui/material/Box';

function RegistrationForm() {
  return (
    <Box component="form">
      <TextField label="Full Name" margin="normal" fullWidth />
      <TextField label="Email" margin="normal" fullWidth />
      <FormControlLabel control={<Checkbox />} label="I agree to the terms and conditions" />
      <Button variant="contained" sx={{ mt: 2 }} fullWidth>Register</Button>
    </Box>
  );
}

export default RegistrationForm;
